enum ParticleNebula: NebulaBackendRenderer {
    // §7 L2 fallback (§10). Soft alpha-falloff billboard sprites read as volumetric
    // haze; solid constant-alpha spheres read as hard-edged blobs, so they're gone.
    // Palette sampled from real Webb/Hubble nebulae (Pillars/Carina/Lagoon) — muted
    // blues + dusty rust/tan, not saturated candy colors (see CREDITS.md).
    @MainActor
    static func make(gen: EnvironmentGenerator) -> Entity {
        let e = Entity(); e.name = "L2_Nebula_Particles"
        var rng = gen.nebulaStream()

        // One soft radial-alpha sprite texture, generated once. White RGB so the
        // per-plane tint shows through; the alpha channel is the falloff.
        let size = 128
        let byteCount = size * size * 4
        let buffer = UnsafeMutableRawPointer.allocate(byteCount: byteCount, alignment: 1)
        defer { buffer.deallocate() }
        let px = buffer.bindMemory(to: UInt8.self, capacity: byteCount)
        for y in 0..<size {
            for x in 0..<size {
                let dx = (Float(x) + 0.5) / Float(size) * 2 - 1
                let dy = (Float(y) + 0.5) / Float(size) * 2 - 1
                let f = max(0, 1 - sqrt(dx * dx + dy * dy))   // 1 at center → 0 at edge
                let i = (y * size + x) * 4
                px[i] = 255; px[i + 1] = 255; px[i + 2] = 255   // white
                px[i + 3] = UInt8(f * f * 255)                  // quadratic falloff
            }
        }

        let colorSpace = CGColorSpace(name: CGColorSpace.sRGB)!
        let bitmapInfo = CGBitmapInfo.byteOrder32Big.rawValue | CGImageAlphaInfo.last.rawValue
        guard let cgImage = CGImage(
            width: size, height: size, bitsPerComponent: 8, bitsPerPixel: 32,
            bytesPerRow: size * 4, space: colorSpace, bitmapInfo: CGBitmapInfo(rawValue: bitmapInfo),
            provider: CGDataProvider(data: Data(bytesNoCopy: px, count: byteCount, deallocator: .none) as CFData)!,
            decode: nil, shouldInterpolate: true, intent: .defaultIntent
        ) else { return e }

        let sprite: TextureResource
        do {
            sprite = try TextureResource.generate(from: cgImage, withName: "nebula_sprite", options: .init(semantic: .color))
        } catch {
            print("[Float] L2 nebula sprite generation failed — \(error)")
            return e
        }

        let palette: [UIColor] = [
            UIColor(red: 0.08, green: 0.17, blue: 0.32, alpha: 1),  // deep blue
            UIColor(red: 0.22, green: 0.29, blue: 0.43, alpha: 1),  // steel blue
            UIColor(red: 0.16, green: 0.30, blue: 0.53, alpha: 1),  // blue
            UIColor(red: 0.52, green: 0.30, blue: 0.23, alpha: 1),  // dusty rust
            UIColor(red: 0.69, green: 0.47, blue: 0.35, alpha: 1),  // warm tan
            UIColor(red: 0.20, green: 0.20, blue: 0.26, alpha: 1),  // muted purple
            UIColor(red: 0.37, green: 0.43, blue: 0.56, alpha: 1)   // lavender-grey
        ]

        // Depth shells give volumetric self-parallax; clustered soft sprites at low
        // alpha accumulate into haze (§2/§3).
        let depthShells: [Float] = [15, 28, 45, 68, 95, 120]
        for depth in depthShells {
            for _ in 0..<3 {                                   // 3 cluster centers per shell
                let azimuth = 2.0 * Float.pi * rng.unit()
                let elevation = (rng.unit() - 0.5) * 0.8
                let cx = depth * cos(elevation) * cos(azimuth)
                let cy = depth * sin(elevation)
                let cz = depth * cos(elevation) * sin(azimuth)
                let clusterColor = palette[Int(rng.unit() * Float(palette.count)) % palette.count]

                let count = 6 + Int(rng.unit() * 5)            // 6..10 planes per cluster
                for _ in 0..<count {
