                    let ox = spread * (rng.unit() + rng.unit() + rng.unit() - 1.5)  // soft gaussian-ish
                    let oy = spread * (rng.unit() + rng.unit() + rng.unit() - 1.5)
                    let oz = spread * (rng.unit() + rng.unit() + rng.unit() - 1.5)

                    let planeSize = depth * (0.25 + 0.45 * rng.unit())
